function solve(s) {
    const frequencies = new Map();
    for (const char of s) {
        frequencies.set(char, (frequencies.get(char) || 0) + 1);
    }

    const getMirror = (char) => {
        const code = char.charCodeAt(0);

        // Lowercase letters (a=97, z=122)
        if (code >= 97 && code <= 122) {
            // a is index 0, z is index 25. Mirror index = 25 - current index.
            const index = code - 97;
            const mirrorCode = 97 + (25 - index);
            return String.fromCharCode(mirrorCode);
        }

        // Digits (0=48, 9=57)
        if (code >= 48 && code <= 57) {
            // 0 is index 0, 9 is index 9. Mirror index = 9 - current index.
            const index = code - 48;
            const mirrorCode = 48 + (9 - index);
            return String.fromCharCode(mirrorCode);
        }

        return char; 
    };

    let totalDifferenceSum = 0;
    const processedPairs = new Set();

    // Get unique characters present in s
    const uniqueChars = Array.from(new Set(s));

    for (const c of uniqueChars) {
        const m = getMirror(c);

        // Determine canonical representation of the pair {c, m}
        // String comparison works lexicographically for ASCII characters (letters then digits).
        // We use min/max to ensure we only process the pair once.
        const pairKey = c < m ? c + m : m + c;

        if (processedPairs.has(pairKey)) {
            continue;
        }

        processedPairs.add(pairKey);

        const freqC = frequencies.get(c); // Guaranteed to exist
        const freqM = frequencies.get(m) || 0; // Might be 0 if m is not in s

        const difference = Math.abs(freqC - freqM);
        totalDifferenceSum += difference;
    }

    return totalDifferenceSum;
}

