import java.util.HashMap;
import java.util.HashSet;
import java.util.Map;
import java.util.Set;

public class Solution {

    private static char getMirror(char c) {
        int code = c;

        // Lowercase letters (a=97, z=122)
        if (code >= 'a' && code <= 'z') {
            // a is index 0, z is index 25. Mirror index = 25 - current index.
            int index = code - 'a';
            int mirrorIndex = 25 - index;
            return (char) ('a' + mirrorIndex);
        }

        // Digits (0=48, 9=57)
        if (code >= '0' && code <= '9') {
            // 0 is index 0, 9 is index 9. Mirror index = 9 - current index.
            int index = code - '0';
            int mirrorIndex = 9 - index;
            return (char) ('0' + mirrorIndex);
        }

        // Should not happen based on constraints
        return c; 
    }

    public static long solve(String s) {
        // Step 1: Frequency Counting
        Map<Character, Integer> frequencies = new HashMap<>();
        for (char c : s.toCharArray()) {
            frequencies.put(c, frequencies.getOrDefault(c, 0) + 1);
        }

        long totalDifferenceSum = 0;
        // Set to track processed pairs using a canonical key (e.g., "char1char2" where char1 <= char2)
        Set<String> processedPairs = new HashSet<>();

        // Get unique characters present in s
        Set<Character> uniqueChars = frequencies.keySet();

        for (char c : uniqueChars) {
            char m = getMirror(c);

            // Determine canonical representation of the pair {c, m}
            // Ensure we process {c, m} only once.
            String pairKey;
            if (c <= m) {
                pairKey = "" + c + m;
            } else {
                pairKey = "" + m + c;
            }

            if (processedPairs.contains(pairKey)) {
                continue;
            }

            processedPairs.add(pairKey);

            // Calculate frequencies
            int freqC = frequencies.get(c); // Guaranteed to exist
            int freqM = frequencies.getOrDefault(m, 0); // Might be 0 if m is not in s

            // Calculate absolute difference
            long difference = Math.abs((long)freqC - freqM);

            totalDifferenceSum += difference;
        }

        return totalDifferenceSum;
    }
}

