import java.util.HashMap;
import java.util.HashSet;
import java.util.Map;
import java.util.Set;

public class Solution {

    private static char getMirror(char c) {
        int code = c;

        // Lowercase letters ('a'=97, 'z'=122)
        if (code >= 'a' && code <= 'z') {
            // 'a' -> 'z', 'b' -> 'y'
            return (char) ('a' + ('z' - c));
        }

        // Digits ('0'=48, '9'=57)
        if (code >= '0' && code <= '9') {
            // '0' -> '9', '1' -> '8'
            return (char) ('0' + ('9' - c));
        }

        // Should not happen based on problem constraints
        return c; 
    }

    public static long solve(String s) {
        // 1. Calculate frequencies
        Map<Character, Integer> frequencies = new HashMap<>();
        for (char c : s.toCharArray()) {
            frequencies.put(c, frequencies.getOrDefault(c, 0) + 1);
        }

        long totalDifferenceSum = 0;
        Set<String> processedPairs = new HashSet<>();

        // 2. Iterate over unique characters present in s
        for (char c : frequencies.keySet()) {
            char m = getMirror(c);

            // Determine canonical representation of the pair {c, m}
            // Ensure we only process {c, m} once.
            char smaller = (c < m) ? c : m;
            char larger = (c < m) ? m : c;

            String pairKey = "" + smaller + larger;

            if (processedPairs.contains(pairKey)) {
                continue;
            }

            processedPairs.add(pairKey);

            // Get frequencies. freq(c) is guaranteed to exist. freq(m) might be 0.
            int freqC = frequencies.get(c); 
            int freqM = frequencies.getOrDefault(m, 0); 

            // Calculate absolute difference
            long difference = Math.abs((long)freqC - freqM);

            totalDifferenceSum += difference;
        }

        return totalDifferenceSum;
    }
}

